/**
 * Rust `xxh3_64` projection for the only byte lengths used by NGram tokenization.
 *
 * Rust reference: `xxhash_rust::xxh3::xxh3_64` through `NGramIndex::hash_str`.
 * @zh NGram 只投影 1-2 byte 短字符串或 3-byte shingle，并保留 Rust 的 31-bit mask。
 */
export function xxh3NGramHash(bytes: Uint8Array): number {
  if (bytes.byteLength > 3) {
    throw new RangeError("xxh3NGramHash only supports NGram short inputs up to 3 bytes")
  }
  return Number(xxh3_64(bytes) & 0x7fffffffn)
}

function isRustAlphanumeric(char: string): boolean {
  return /^[\p{Alphabetic}\p{Number}]$/u.test(char)
}

/**
 * Tokenize text into character trigram hashes.
 * Rust reference: `NGramIndex::tokenize` (`../src/ngram.rs`).
 * @zh 规范化文本后按 UTF-8 byte trigram 取 `xxh3_64 & 0x7fffffff`。
 */
export function tokenizeNGram(text: string): ReadonlyArray<number> {
  const normalized = Array.from(text.toLowerCase(), (char) =>
    isRustAlphanumeric(char) ? char : " "
  ).join("")
  const clean = normalized.split(/\s+/u).filter((part) => part.length > 0).join(" ")
  if (clean.length === 0) return []

  const bytes = te.encode(clean)
  if (bytes.byteLength < 3) return [xxh3NGramHash(bytes)]

  const shingles: number[] = []
  for (let i = 0; i <= bytes.byteLength - 3; i++) {
    shingles.push(xxh3NGramHash(bytes.subarray(i, i + 3)))
  }
  shingles.sort((a, b) => a - b)

  let write = 0
  for (const shingle of shingles) {
    if (write === 0 || shingles[write - 1] !== shingle) {
      shingles[write] = shingle
      write += 1
    }
  }
  shingles.length = write
  return shingles
}

/**
 * Draw a 31-bit unsigned integer from Web Crypto.
 * @zh Rust `gen_range` 的目标 PRIME 小于 2^31，因此先取 31-bit 空间再做拒绝采样。
 */
function randomU31(): number {
  const crypto = globalThis.crypto
  if (crypto === undefined) {
    throw new Error("NGramIndex.random requires globalThis.crypto.getRandomValues")
  }
  crypto.getRandomValues(randomBuffer)
  return randomBuffer[0]! >>> 1
}

/**
 * Draw an unbiased integer in `[0, exclusiveMax)`.
 * @zh 丢弃不能整除目标区间的尾部值，避免 modulo bias。
 */
function randomIntBelow(exclusiveMax: number): number {
  const limit = Math.floor(U31_SPACE / exclusiveMax) * exclusiveMax
  while (true) {
    const value = randomU31()
    if (value < limit) return value % exclusiveMax
  }
}

function randomCoefficientA(): number {
  return 1 + randomIntBelow(PRIME - 1)
}

function randomCoefficientB(): number {
  return randomIntBelow(PRIME)
}

/**
 * MinHash-based n-gram index for approximate Jaccard similarity.
 *
 * 基于 MinHash 的 n-gram 索引，用于近似 Jaccard 相似度。
 *
 * Rust reference: `NGramIndex` in `../src/ngram.rs`.
 */
export class NGramIndex {
  private readonly aBig: ReadonlyArray<bigint>
  private readonly bBig: ReadonlyArray<bigint>
  private readonly signatures = new Map<string, ReadonlyArray<number>>()
  private readonly buckets: Array<Map<number, string[]>>

  private constructor(
    private readonly a: ReadonlyArray<number>,
    b: ReadonlyArray<number>,
    private readonly synonymRing?: SynonymRing
  ) {
    if (a.length !== b.length || a.length === 0) {
      throw new RangeError("NGramIndex requires non-empty equal coefficient arrays")
    }
    this.aBig = a.map(BigInt)
    this.bBig = b.map(BigInt)
    this.buckets = Array.from({ length: a.length }, () => new Map<number, string[]>())
  }

  /**
   * Create a new n-gram index.
   * 创建新的 n-gram 索引。
   * Rust reference: `NGramIndex::new` (`../src/ngram.rs`).
   * @zh 使用 Web Crypto 随机源 + rejection sampling，对齐 Rust `gen_range(1..PRIME)`
   * / `gen_range(0..PRIME)` 的整数区间分布；跨语言确定性 verifier 仍使用 `withSeed0`。
   */
  static random(numHashes = DEFAULT_NUM_HASHES, synonymRing?: SynonymRing): NGramIndex {
    const a = Array.from({ length: numHashes }, randomCoefficientA)
    const b = Array.from({ length: numHashes }, randomCoefficientB)
    return new NGramIndex(a, b, synonymRing)
  }

  /**
   * Create the deterministic verifier index equivalent to Rust `with_seed(None, None, 0)`.
   * 创建与 Rust verifier 等价的确定性索引。
   */
  static withSeed0(synonymRing?: SynonymRing): NGramIndex {
    return new NGramIndex(RUST_SEED_0_A, RUST_SEED_0_B, synonymRing)
  }

  /**
   * Expand text using synonym ring.
   * 使用 synonym ring 扩展文本。
   * Rust reference: `NGramIndex::expand` (`../src/ngram.rs`).
   */
  private expand(text: string): string {
    return this.synonymRing?.expand(text) ?? text
  }

  /**
   * Compute MinHash signature for a set of shingles.
   * 为 shingle 集合计算 MinHash 签名。
   */
  private minhash(shingles: ReadonlyArray<number>): ReadonlyArray<number> {
    const sig = Array<number>(this.a.length).fill(Number.MAX_SAFE_INTEGER)
    for (const s of shingles) {
      const sBig = BigInt(s)
      for (let i = 0; i < sig.length; i++) {
        const h = Number(((this.aBig[i]! * sBig) + this.bBig[i]!) % PRIME_BIGINT)
        if (h < sig[i]!) sig[i] = h
      }
    }
    return sig
  }

  /**
   * Index a record.
   * 为记录建立索引。
   */
  add(recordId: string, text: string): void {
    const shingles = tokenizeNGram(this.expand(text))
    if (shingles.length === 0) return

    const sig = this.minhash(shingles)

    // Populate LSH buckets.
    for (let i = 0; i < sig.length; i++) {
      const val = sig[i]!
      const bucket = this.buckets[i]!.get(val) ?? []
      bucket.push(recordId)
      this.buckets[i]!.set(val, bucket)
    }

    this.signatures.set(recordId, sig)
  }

  /**
   * Remove a record from the index.
   * 从索引中移除记录。
   */
  remove(recordId: string): void {
    const sig = this.signatures.get(recordId)
    if (!sig) return
    this.signatures.delete(recordId)

    for (let i = 0; i < sig.length; i++) {
      const bucket = this.buckets[i]!.get(sig[i]!)
      if (!bucket) continue
      const retained = bucket.filter((id) => id !== recordId)
      if (retained.length === 0) {
        this.buckets[i]!.delete(sig[i]!)
      } else {
        this.buckets[i]!.set(sig[i]!, retained)
      }
    }
  }

  /**
   * Query for similar records using LSH.
   *
   * Returns `[(similarity, record_id), ...]` sorted descending.
   * 使用 LSH 查询相似记录；返回按相似度降序排列的 `[(similarity, record_id), ...]`。
   */
  query(text: string, topK: number): Array<[number, string]> {
    if (topK <= 0) return []
    const shingles = tokenizeNGram(this.expand(text))
    if (shingles.length === 0) return []

    const querySig = this.minhash(shingles)
    const candidates = new Map<string, number>()
    for (let i = 0; i < querySig.length; i++) {
      const bucket = this.buckets[i]!.get(querySig[i]!)
      if (!bucket) continue
      for (const rid of bucket) {
        candidates.set(rid, (candidates.get(rid) ?? 0) + 1)
      }
    }

    const results: Array<[number, string]> = []
    for (const [rid, count] of candidates) {
      const similarity = count / this.a.length
      if (similarity > 0) results.push([similarity, rid])
    }
    results.sort((left, right) => right[0] - left[0])
    results.length = Math.min(results.length, topK)
    return results
  }

  /**
   * Compute exact Jaccard similarity between two record signatures.
   * @zh 计算两个记录签名之间的 Jaccard 估计值。
   */
  jaccard(idA: string, idB: string): number {
    const sigA = this.signatures.get(idA)
    const sigB = this.signatures.get(idB)
    if (!sigA || !sigB) return 0

    let matching = 0
    for (let i = 0; i < sigA.length; i++) {
      if (sigA[i] === sigB[i]) matching += 1
    }
    return matching / this.a.length
  }

  /**
   * Find all pairs with Jaccard similarity >= threshold.
   * @zh 查找相似度不低于阈值的记录对。
   */
  findSimilarPairs(threshold: number): Array<[string, string, number]> {
    const ids = Array.from(this.signatures.keys())
    const pairs: Array<[string, string, number]> = []
    for (let i = 0; i < ids.length; i++) {
      for (let j = i + 1; j < ids.length; j++) {
        const sim = this.jaccard(ids[i]!, ids[j]!)
        if (sim >= threshold) pairs.push([ids[i]!, ids[j]!, sim])
      }
    }
    return pairs
  }

  /**
   * Number of indexed records.
   * @zh 返回已索引记录数量。
   */
  len(): number {
    return this.signatures.size
  }

  isEmpty(): boolean {
    return this.signatures.size === 0
  }

  /**
   * Check if a record is indexed.
   * @zh 检查记录是否已索引。
   */
  contains(recordId: string): boolean {
    return this.signatures.has(recordId)
  }
}
